<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Ubuntu Desktop</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  html, body { height: 100%; overflow: hidden; font-family: "Segoe UI", Ubuntu, Arial, sans-serif; }
  body { background: #2b2b2b; color: #fff; }

  #desktop {
    position: relative;
    width: 100vw;
    height: 100vh;
    background:
      radial-gradient(circle at 30% 20%, #5e2750 0%, transparent 45%),
      radial-gradient(circle at 75% 70%, #1c3d5a 0%, transparent 50%),
      linear-gradient(135deg, #2c001e 0%, #1a1a2e 100%);
    overflow: hidden;
  }

  /* Top bar */
  #topbar {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 28px;
    background: rgba(20, 20, 20, 0.85);
    backdrop-filter: blur(6px);
    display: flex;
    align-items: center;
    padding: 0 12px;
    font-size: 13px;
    color: #fff;
    z-index: 1000;
    border-bottom: 1px solid rgba(255,255,255,0.05);
  }
  #topbar .activities { cursor: pointer; padding: 0 8px; }
  #topbar .clock { position: absolute; left: 50%; transform: translateX(-50%); }
  #topbar .icons { margin-left: auto; display: flex; gap: 10px; opacity: 0.9; }

  /* Desktop icons */
  .desk-icon {
    position: absolute;
    width: 84px;
    text-align: center;
    color: #fff;
    font-size: 12px;
    text-shadow: 0 1px 3px rgba(0,0,0,0.7);
    cursor: default;
    user-select: none;
    padding: 6px;
    border-radius: 6px;
  }
  .desk-icon:hover { background: rgba(255,255,255,0.1); }
  .desk-icon .glyph {
    font-size: 38px;
    line-height: 1;
    margin-bottom: 4px;
    display: block;
  }

  /* Taskbar / dock */
  #taskbar {
    position: absolute;
    bottom: 8px;
    left: 50%;
    transform: translateX(-50%);
    display: flex;
    gap: 8px;
    padding: 8px 12px;
    background: rgba(30, 30, 30, 0.75);
    backdrop-filter: blur(10px);
    border: 1px solid rgba(255,255,255,0.08);
    border-radius: 16px;
    z-index: 1000;
    box-shadow: 0 6px 20px rgba(0,0,0,0.4);
  }
  #taskbar button {
    width: 48px; height: 48px;
    border: none;
    border-radius: 10px;
    background: rgba(255,255,255,0.06);
    color: #fff;
    font-size: 24px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.15s, transform 0.1s;
  }
  #taskbar button:hover { background: rgba(255,255,255,0.18); transform: translateY(-2px); }
  #taskbar button:active { transform: translateY(0); }
  #taskbar button.active { background: rgba(233, 84, 32, 0.5); }

  /* Windows */
  .window {
    position: absolute;
    min-width: 360px;
    min-height: 240px;
    background: #383838;
    border: 1px solid rgba(0,0,0,0.5);
    border-radius: 8px;
    box-shadow: 0 12px 40px rgba(0,0,0,0.5);
    display: flex;
    flex-direction: column;
    overflow: hidden;
    z-index: 10;
  }
  .window.hidden { display: none !important; }
  .win-titlebar {
    height: 34px;
    background: linear-gradient(#3c3c3c, #2f2f2f);
    display: flex;
    align-items: center;
    padding: 0 10px;
    cursor: grab;
    user-select: none;
    border-bottom: 1px solid rgba(0,0,0,0.4);
  }
  .win-titlebar:active { cursor: grabbing; }
  .win-title { flex: 1; font-size: 13px; color: #eee; }
  .win-controls { display: flex; gap: 8px; }
  .win-btn {
    width: 14px; height: 14px; border-radius: 50%;
    border: none; cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    font-size: 9px; color: rgba(0,0,0,0.55);
  }
  .win-close { background: #e95420; }
  .win-min { background: #f5b50e; }
  .win-max { background: #5fd35f; }
  .win-btn:hover { filter: brightness(1.15); }
  .win-body { flex: 1; overflow: auto; position: relative; }

  /* Files app */
  #files-window { width: 560px; height: 380px; left: 80px; top: 70px; }
  .files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 10px;
    background: #2f2f2f;
    border-bottom: 1px solid rgba(0,0,0,0.3);
  }
  #files-up {
    padding: 4px 10px;
    background: #4a4a4a;
    color: #fff;
    border: 1px solid rgba(0,0,0,0.4);
    border-radius: 4px;
    cursor: pointer;
    font-size: 13px;
  }
  #files-up:hover { background: #5a5a5a; }
  #files-path {
    flex: 1;
    background: #2a2a2a;
    color: #ddd;
    border: 1px solid rgba(0,0,0,0.4);
    border-radius: 4px;
    padding: 5px 8px;
    font-family: monospace;
    font-size: 13px;
  }
  .files-list {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(96px, 1fr));
    gap: 6px;
    padding: 14px;
  }
  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 10px 4px;
    border-radius: 6px;
    cursor: pointer;
    color: #eee;
    font-size: 12px;
    text-align: center;
    user-select: none;
  }
  .fs-item:hover { background: rgba(255,255,255,0.08); }
  .fs-item.selected { background: rgba(233, 84, 32, 0.35); }
  .fs-item .icon { font-size: 34px; line-height: 1; margin-bottom: 6px; }
  .fs-item .name { word-break: break-word; max-width: 90px; }

  /* Notepad app */
  #notepad-window { width: 520px; height: 400px; left: 200px; top: 110px; }
  .notepad-tabs {
    display: flex;
    align-items: center;
    background: #2f2f2f;
    border-bottom: 1px solid rgba(0,0,0,0.4);
    padding: 4px 6px 0 6px;
    gap: 4px;
    min-height: 34px;
  }
  .tab {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 5px 10px;
    background: #3a3a3a;
    border-radius: 6px 6px 0 0;
    color: #ccc;
    font-size: 12px;
    cursor: pointer;
    max-width: 140px;
    border: 1px solid rgba(0,0,0,0.3);
    border-bottom: none;
  }
  .tab.active {
    background: #4a4a4a;
    color: #fff;
  }
  .tab .tab-name {
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: 100px;
  }
  .tab .tab-close {
    width: 16px; height: 16px;
    border-radius: 50%;
    background: rgba(255,255,255,0.1);
    display: flex; align-items: center; justify-content: center;
    font-size: 11px;
    cursor: pointer;
  }
  .tab .tab-close:hover { background: rgba(255,80,80,0.6); }
  #new-tab {
    padding: 5px 10px;
    background: transparent;
    color: #ddd;
    border: 1px dashed rgba(255,255,255,0.25);
    border-radius: 6px;
    cursor: pointer;
    font-size: 14px;
  }
  #new-tab:hover { background: rgba(255,255,255,0.08); }
  #editor {
    flex: 1;
    width: 100%;
    border: none;
    outline: none;
    resize: none;
    background: #1e1e1e;
    color: #e8e8e8;
    font-family: "Consolas", "Ubuntu Mono", monospace;
    font-size: 14px;
    padding: 12px;
    line-height: 1.5;
  }
  .notepad-status {
    background: #2a2a2a;
    color: #aaa;
    font-size: 11px;
    padding: 3px 10px;
    border-top: 1px solid rgba(0,0,0,0.3);
    display: flex;
    justify-content: space-between;
  }
</style>
</head>
