<script>
(function () {
  "use strict";

  /* ---------- Filesystem data ---------- */
  const FS = {
    "/": { type: "dir", children: ["bin", "etc", "home", "usr", "var", "tmp", "opt"] },
    "/bin": { type: "dir", children: ["bash", "ls", "cp", "mv", "cat"] },
    "/bin/bash": { type: "file", content: "ELF binary (fake)" },
    "/bin/ls": { type: "file", content: "ELF binary (fake)" },
    "/bin/cp": { type: "file", content: "ELF binary (fake)" },
    "/bin/mv": { type: "file", content: "ELF binary (fake)" },
    "/bin/cat": { type: "file", content: "ELF binary (fake)" },

    "/etc": { type: "dir", children: ["hostname", "passwd", "fstab", "apt"] },
    "/etc/hostname": { type: "file", content: "ubuntu-desktop" },
    "/etc/passwd": { type: "file", content: "root:x:0:0:root:/root:/bin/bash\nuser:x:1000:1000:user:/home/user:/bin/bash" },
    "/etc/fstab": { type: "file", content: "/dev/sda1 / ext4 defaults 0 1" },
    "/etc/apt": { type: "dir", children: ["sources.list"] },
    "/etc/apt/sources.list": { type: "file", content: "deb http://archive.ubuntu.com focal main" },

    "/home": { type: "dir", children: ["user"] },
    "/home/user": { type: "dir", children: ["Documents", "Downloads", "Pictures", "Music", ".bashrc", "notes.txt"] },
    "/home/user/.bashrc": { type: "file", content: "# ~/.bashrc\nexport PS1='\\u@\\h:\\w$ '" },
    "/home/user/notes.txt": { type: "file", content: "Remember to buy milk." },

    "/home/user/Documents": { type: "dir", children: ["report.txt", "todo.md"] },
    "/home/user/Documents/report.txt": { type: "file", content: "Quarterly report draft..." },
    "/home/user/Documents/todo.md": { type: "file", content: "# TODO\n- [ ] finish report\n- [x] setup desktop" },

    "/home/user/Downloads": { type: "dir", children: ["ubuntu-20.04.iso", "installer.deb"] },
    "/home/user/Downloads/ubuntu-20.04.iso": { type: "file", content: "ISO image (fake)" },
    "/home/user/Downloads/installer.deb": { type: "file", content: "Debian package (fake)" },

    "/home/user/Pictures": { type: "dir", children: ["wallpaper.png", "photo.jpg"] },
    "/home/user/Pictures/wallpaper.png": { type: "file", content: "PNG image (fake)" },
    "/home/user/Pictures/photo.jpg": { type: "file", content: "JPEG image (fake)" },

    "/home/user/Music": { type: "dir", children: ["song.mp3"] },
    "/home/user/Music/song.mp3": { type: "file", content: "MP3 audio (fake)" },

    "/usr": { type: "dir", children: ["bin", "lib", "share"] },
    "/usr/bin": { type: "dir", children: ["python3", "git"] },
    "/usr/bin/python3": { type: "file", content: "ELF binary (fake)" },
    "/usr/bin/git": { type: "file", content: "ELF binary (fake)" },
    "/usr/lib": { type: "dir", children: ["libc.so"] },
    "/usr/lib/libc.so": { type: "file", content: "Shared library (fake)" },
    "/usr/share": { type: "dir", children: ["doc", "icons"] },
    "/usr/share/doc": { type: "dir", children: ["README"] },
    "/usr/share/doc/README": { type: "file", content: "Documentation root." },
    "/usr/share/icons": { type: "dir", children: ["hicolor"] },
    "/usr/share/icons/hicolor": { type: "dir", children: [] },

    "/var": { type: "dir", children: ["log", "tmp", "lib"] },
    "/var/log": { type: "dir", children: ["syslog", "auth.log"] },
    "/var/log/syslog": { type: "file", content: "system boot started..." },
    "/var/log/auth.log": { type: "file", content: "user logged in." },
    "/var/tmp": { type: "dir", children: [] },
    "/var/lib": { type: "dir", children: ["dpkg"] },
    "/var/lib/dpkg": { type: "dir", children: ["status"] },
    "/var/lib/dpkg/status": { type: "file", content: "package db" },

    "/tmp": { type: "dir", children: [] },
    "/opt": { type: "dir", children: [] }
  };

  function normalize(path) {
    const parts = path.split("/").filter(Boolean);
    const stack = [];
    for (const p of parts) {
      if (p === ".") continue;
      if (p === "..") stack.pop();
      else stack.push(p);
    }
    return "/" + stack.join("/");
  }
  function parentOf(path) {
    if (path === "/") return "/";
    const parts = path.split("/").filter(Boolean);
    parts.pop();
    return "/" + parts.join("/");
  }
  function entryAt(path) {
    const p = normalize(path) === "" ? "/" : normalize(path);
    return FS[p === "" ? "/" : p];
  }
  function iconFor(name, isDir) {
    if (isDir) return "📁";
    if (/\.(png|jpg|jpeg|gif|svg)$/.test(name)) return "🖼️";
    if (/\.(mp3|wav|ogg)$/.test(name)) return "🎵";
    if (/\.(iso|img)$/.test(name)) return "💿";
    if (/\.(deb|rpm)$/.test(name)) return "📦";
    if (/\.(so|so\..*)$/.test(name)) return "🔧";
    if (name === "bash" || name === "sh") return "⚙️";
    return "📄";
  }

  /* ---------- Files app ---------- */
  const filesWindow = document.getElementById("files-window");
  const filesPath = document.getElementById("files-path");
  const filesList = document.getElementById("files-list");
  const filesUp = document.getElementById("files-up");
  let currentPath = "/";

  function renderFiles() {
    filesPath.value = currentPath;
    filesList.innerHTML = "";
    const entry = entryAt(currentPath);
    if (!entry || entry.type !== "dir") return;
    const kids = entry.children || [];
    kids.forEach(name => {
      const childPath = normalize(currentPath + "/" + name);
      const child = entryAt(childPath);
      const isDir = child && child.type === "dir";
      const item = document.createElement("div");
      item.className = "fs-item";
      item.dataset.path = childPath;
      item.dataset.name = name;
      item.dataset.isdir = isDir ? "1" : "0";
      item.innerHTML =
        '<span class="icon">' + iconFor(name, isDir) + "</span>" +
        '<span class="name">' + name + "</span>";
      item.addEventListener("click", () => {
        document.querySelectorAll(".fs-item.selected").forEach(s => s.classList.remove("selected"));
        item.classList.add("selected");
      });
      item.addEventListener("dblclick", () => {
        if (isDir) {
          currentPath = childPath === "" ? "/" : childPath;
          renderFiles();
        } else {
          // open file content in notepad as a new tab
          openNotepad();
          const content = (child && child.content) || "";
          createTab(name, content);
        }
      });
      filesList.appendChild(item);
    });
  }
  filesUp.addEventListener("click", () => {
    currentPath = parentOf(currentPath);
    renderFiles();
  });

  /* ---------- Window helpers ---------- */
  function showWindow(win) {
    win.classList.remove("hidden");
    bringToFront(win);
  }
  function hideWindow(win) { win.classList.add("hidden"); }
  let zCounter = 10;
  function bringToFront(win) {
    zCounter += 1;
    win.style.zIndex = zCounter;
  }

  document.getElementById("open-files").addEventListener("click", () => {
    if (filesWindow.classList.contains("hidden")) showWindow(filesWindow);
    else bringToFront(filesWindow);
    renderFiles();
  });
  document.getElementById("open-notepad").addEventListener("click", () => {
    openNotepad();
  });
  function openNotepad() {
    if (notepadWindow.classList.contains("hidden")) showWindow(notepadWindow);
    else bringToFront(notepadWindow);
    ensureTabs();
  }

  /* Close buttons */
  document.querySelectorAll(".win-close").forEach(btn => {
    btn.addEventListener("click", (e) => {
      e.stopPropagation();
      const win = btn.closest(".window");
      hideWindow(win);
    });
  });
  /* Minimize = hide */
  document.querySelectorAll(".win-min").forEach(btn => {
    btn.addEventListener("click", (e) => {
      e.stopPropagation();
      const win = btn.closest(".window");
      hideWindow(win);
    });
  });
  /* Maximize toggle */
  document.querySelectorAll(".win-max").forEach(btn => {
    btn.addEventListener("click", (e) => {
      e.stopPropagation();
      const win = btn.closest(".window");
      if (win.dataset.maxd === "1") {
        win.style.left = win.dataset.prevLeft;
        win.style.top = win.dataset.prevTop;
        win.style.width = win.dataset.prevW;
        win.style.height = win.dataset.prevH;
        win.dataset.maxd = "0";
      } else {
        win.dataset.prevLeft = win.style.left;
        win.dataset.prevTop = win.style.top;
        win.dataset.prevW = win.style.width;
        win.dataset.prevH = win.style.height;
        win.style.left = "0px";
        win.style.top = "28px";
        win.style.width = "100vw";
        win.style.height = "calc(100vh - 28px - 80px)";
        win.dataset.maxd = "1";
      }
    });
  });

  /* Dragging */
  document.querySelectorAll("[data-drag]").forEach(bar => {
    bar.addEventListener("mousedown", (e) => {
      if (e.target.classList.contains("win-btn")) return;
      const win = bar.closest(".window");
      bringToFront(win);
      const startX = e.clientX, startY = e.clientY;
      const rect = win.getBoundingClientRect();
      const offX = startX - rect.left, offY = startY - rect.top;
      function move(ev) {
        let x = ev.clientX - offX;
        let y = ev.clientY - offY;
        y = Math.max(28, y);
        win.style.left = x + "px";
        win.style.top = y + "px";
      }
      function up() {
        document.removeEventListener("mousemove", move);
        document.removeEventListener("mouseup", up);
      }
      document.addEventListener("mousemove", move);
      document.addEventListener("mouseup", up);
    });
  });

  /* ---------- Notepad app ---------- */
  const notepadWindow = document.getElementById("notepad-window");
  const tabsEl = document.getElementById("tabs");
  const newTabBtn = document.getElementById("new-tab");
  const editor = document.getElementById("editor");
  const statusTab = document.getElementById("np-status-tab");
  const statusInfo = document.getElementById("np-status-info");

  const STORE_KEY = "ubuntu_notepad_tabs_v1";
  let tabs = []; // [{id, name, content}]
  let activeId = null;

  function loadState() {
    try {
      const raw = localStorage.getItem(STORE_KEY);
      if (raw) {
        const data = JSON.parse(raw);
        if (data && Array.isArray(data.tabs)) {
          tabs = data.tabs.map(t => ({ id: t.id || genId(), name: t.name || "Untitled", content: t.content || "" }));
          activeId = data.activeId && tabs.some(t => t.id === data.activeId) ? data.activeId : (tabs[0] ? tabs[0].id : null);
        }
      }
    } catch (e) { console.warn("load failed", e); }
  }
  function saveState() {
    try {
      localStorage.setItem(STORE_KEY, JSON.stringify({ tabs, activeId }));
    } catch (e) { console.warn("save failed", e); }
  }
  function genId() { return "tab_" + Math.random().toString(36).slice(2, 9); }

  function renderTabs() {
    // remove existing .tab elements (keep #new-tab)
    tabsEl.querySelectorAll(".tab").forEach(t => t.remove());
    tabs.forEach(t => {
      const el = document.createElement("div");
      el.className = "tab" + (t.id === activeId ? " active" : "");
      el.dataset.id = t.id;
      const name = document.createElement("span");
      name.className = "tab-name";
      name.textContent = t.name;
      const close = document.createElement("span");
      close.className = "tab-close";
      close.textContent = "×";
      close.addEventListener("click", (e) => {
        e.stopPropagation();
        closeTab(t.id);
      });
      el.addEventListener("click", () => activateTab(t.id));
      el.appendChild(name);
      el.appendChild(close);
      tabsEl.insertBefore(el, newTabBtn);
    });
    updateEditor();
  }
  function updateEditor() {
    const active = tabs.find(t => t.id === activeId);
    if (active) {
      editor.value = active.content;
      editor.disabled = false;
      statusTab.textContent = "Tab: " + active.name;
      statusInfo.textContent = active.content.length + " chars";
    } else {
      editor.value = "";
      editor.disabled = true;
      statusTab.textContent = "No tabs";
      statusInfo.textContent = "0 chars";
    }
  }
  function activateTab(id) {
    activeId = id;
    renderTabs();
    saveState();
  }
  function createTab(name, content) {
    const t = { id: genId(), name: name || "Untitled", content: content || "" };
    tabs.push(t);
    activeId = t.id;
    renderTabs();
    saveState();
    return t;
  }
  function closeTab(id) {
    const idx = tabs.findIndex(t => t.id === id);
    if (idx === -1) return;
    tabs.splice(idx, 1);
    if (activeId === id) {
      activeId = tabs[idx] ? tabs[idx].id : (tabs[idx - 1] ? tabs[idx - 1].id : (tabs[0] ? tabs[0].id : null));
    }
    renderTabs();
    saveState();
